{
  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "Should the D3.js force-directed graph replace the existing BayesNetGraph circular-layout SVG component, or coexist as an alternative view?",
      "category": "requirements",
      "why_it_matters": "BayesNetGraph.tsx (337 lines) already renders network topology with a circular layout. Replacing it changes the UX for existing users; coexisting means maintaining two graph renderers."
    },
    {
      "id": "q2",
      "question": "What does 'interactive node editing (click to view/edit CPT)' mean concretely — editing the raw conditional probability table values, or using the existing ConditionalEditor/VariableRow UI to set outcome probabilities?",
      "category": "requirements",
      "why_it_matters": "The frontend already has ConditionalEditor.tsx (289 lines) and VariableRow.tsx (231 lines) for editing probabilities. A raw CPT editor is a fundamentally different component with matrix-style input, whereas reusing existing components is much simpler."
    },
    {
      "id": "q3",
      "question": "What backend API endpoints exist for evidence propagation, and does the inference engine support step-by-step propagation results needed for animation?",
      "category": "codebase",
      "why_it_matters": "The backend's CurrentModelQueryBackend supports query_marginals() and query_conditional(), but animation requires intermediate states during propagation. If the backend only returns final results, we'd need to simulate intermediate steps on the frontend."
    },
    {
      "id": "q4",
      "question": "What JSON format should the export/import use — the existing API response format (MarketDetailResponse), a custom BN interchange format (e.g. BIF/XMLBIF), or a new schema?",
      "category": "design",
      "why_it_matters": "Using the existing API types is simplest but couples to the server schema. A standard BN format enables interop with external tools but requires a translation layer. This is a fundamental design decision that affects the entire import/export feature."
    },
    {
      "id": "q5",
      "question": "Should undo/redo track only local graph edits (node positions, visual layout) or also server-side mutations (probability edits, evidence submissions)?",
      "category": "requirements",
      "why_it_matters": "Local-only undo is a simple state stack. Server-side undo requires reversing API mutations, which may not be idempotent — the existing mutation hooks (useProbabilityEdit, useEventTrade) don't support rollback and the backend may not have reversal endpoints."
    },
    {
      "id": "q6",
      "question": "Is adding D3.js as a dependency acceptable, or should we continue the project's pattern of custom SVG rendering without external visualization libraries?",
      "category": "design",
      "why_it_matters": "The codebase currently has zero visualization libraries — PriceChart, VolumeChart, and BayesNetGraph all use hand-rolled SVG. Adding D3.js (~250KB) changes the dependency philosophy. A force-directed layout can be implemented without D3 but requires more custom code."
    },
    {
      "id": "q7",
      "question": "How should animation state be managed — via CSS transitions, requestAnimationFrame, or a React animation library (framer-motion, react-spring)?",
      "category": "design",
      "why_it_matters": "Evidence propagation animation needs smooth transitions across multiple nodes simultaneously. The project has no animation library currently. CSS transitions are lightest but limited; requestAnimationFrame gives full control but is complex; a library adds dependency weight."
    },
    {
      "id": "q8",
      "question": "What are the expected network sizes — tens of nodes, hundreds, or thousands? This determines whether force simulation performance is a concern.",
      "category": "requirements",
      "why_it_matters": "D3 force simulation with >100 nodes needs optimization (web workers, canvas rendering instead of SVG). The existing BayesNetGraph renders all markets as nodes, and the current dataset size is unclear."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "D3.js will replace the existing BayesNetGraph component rather than coexisting alongside it",
      "confidence": 0.6,
      "if_wrong": "Need to maintain two graph components and add a view-switcher UI, increasing scope by ~30%"
    },
    {
      "id": "a2",
      "assumption": "CPT editing means a modal/panel with a probability table that opens when clicking a graph node, reusing existing probability edit API endpoints",
      "confidence": 0.7,
      "if_wrong": "If it means a full matrix editor for joint distributions, the component complexity increases significantly and may need new backend endpoints"
    },
    {
      "id": "a3",
      "assumption": "Evidence propagation animation will simulate intermediate steps on the frontend since the backend likely returns only final marginals",
      "confidence": 0.75,
      "if_wrong": "If the backend can stream intermediate inference steps, the animation architecture changes completely — we'd use SSE/WebSocket instead of client-side simulation"
    },
    {
      "id": "a4",
      "assumption": "Export/import will use a custom JSON schema based on the existing API types (markets, outcomes, probabilities, edges)",
      "confidence": 0.65,
      "if_wrong": "If standard BN formats (BIF, XDSL) are required, we need parsing/serialization libraries and a translation layer"
    },
    {
      "id": "a5",
      "assumption": "Undo/redo tracks local editing state only (graph layout, unsaved CPT edits, evidence selections) — not server-side mutations",
      "confidence": 0.7,
      "if_wrong": "Server-side undo requires backend support for reversal operations that may not exist, significantly expanding scope"
    },
    {
      "id": "a6",
      "assumption": "Network sizes will be small to medium (under 50 nodes), consistent with typical Bayesian network applications for markets",
      "confidence": 0.8,
      "if_wrong": "Large networks (100+ nodes) would require canvas-based rendering, web workers for force simulation, and virtualization for the CPT editor"
    },
    {
      "id": "a7",
      "assumption": "The existing React Query + Context API state management is sufficient — no need for a dedicated state management library like Zustand or Redux",
      "confidence": 0.6,
      "if_wrong": "Undo/redo with complex graph state might benefit from a dedicated store with time-travel debugging; would need to add a new dependency"
    }
  ],
  "decomposition_assessment": {
    "complexity_score": 5,
    "complexity_reason": "Five distinct features (D3 graph, CPT editor, animation, import/export, undo/redo) requiring 10+ new/modified files across visualization, state management, and UI layers. New dependency (D3.js), new state patterns (undo/redo command stack), and algorithm integration (propagation animation). Estimated 1500-2500 lines of new code.",
    "uncertainty_score": 4,
    "uncertainty_reason": "Unclear requirements around CPT editing scope, animation approach, and export format. D3.js integration with existing custom-SVG patterns is untested in this codebase. Backend propagation API capabilities are unknown. Undo/redo scope (local vs server) has major architectural implications.",
    "independent_subproblems": [
      "D3.js force-directed graph replacing/extending BayesNetGraph with interactive layout",
      "CPT viewer/editor panel triggered by node click with probability editing",
      "Evidence propagation animation system with visual state transitions",
      "Network JSON export/import with file download/upload UI",
      "Undo/redo state management system with command pattern"
    ],
    "decision": "SPAWN_CHILDREN",
    "decision_reason": "Complexity 5 with 5 clearly independent subproblems that can be developed and tested in isolation. Each subproblem has its own file scope, dependencies, and testing surface. The D3 graph, CPT editor, animation, export/import, and undo/redo are loosely coupled — they share the graph data model but have no build-order dependencies. Parallel development will be significantly faster."
  },
  "spawn_children": true,
  "children": [
    {
      "id": "child-1",
      "title": "D3.js force-directed network graph",
      "description": "Replace or extend BayesNetGraph.tsx with a D3.js force-directed layout. Add d3-force and d3-selection dependencies. Implement draggable nodes showing market title and probability bars, directed edges for conditional dependencies, clique overlays, zoom/pan, and responsive sizing. Preserve existing data flow from useMarket/useEngineStats hooks. Include node click callback for CPT editor integration."
    },
    {
      "id": "child-2",
      "title": "Interactive CPT viewer/editor panel",
      "description": "Create a CPT (Conditional Probability Table) panel component that opens when a graph node is clicked. Display the node's current marginal probabilities and conditional dependencies. Allow inline editing of probability values with validation (must sum to 1.0). Integrate with existing useProbabilityEdit mutation hook for persistence. Support both unconditional and conditional probability views. Follow existing inline-styling patterns with CSS custom properties."
    },
    {
      "id": "child-3",
      "title": "Evidence propagation animation",
      "description": "Implement visual animation showing how setting evidence on one node propagates probability updates through the network. When evidence is set (via CPT editor or assumption panel), animate: 1) highlight the evidence node, 2) show 'wave' spreading along edges to connected nodes, 3) animate probability bar transitions on affected nodes. Use requestAnimationFrame or CSS transitions. Integrate with the D3 graph's node/edge references. Frontend-simulated intermediate steps since backend returns only final marginals."
    },
    {
      "id": "child-4",
      "title": "Network JSON export/import",
      "description": "Add export and import functionality for the Bayesian network. Export: serialize current network state (nodes with markets/outcomes/probabilities, edges with conditional dependencies, layout positions) to a JSON file and trigger browser download. Import: file upload UI that parses JSON, validates schema, and loads the network. Design a clean JSON schema based on existing API types (MarketSummary, CliqueSummary). Add UI buttons in the graph toolbar area."
    },
    {
      "id": "child-5",
      "title": "Undo/redo system for graph edits",
      "description": "Implement an undo/redo system tracking local graph editing operations: node position changes, CPT probability edits (before server submission), evidence toggle, and layout changes. Use a command pattern with an action history stack. Create a React context (HistoryContext) providing undo(), redo(), canUndo, canRedo. Add keyboard shortcuts (Ctrl+Z / Ctrl+Shift+Z). Add undo/redo buttons in the graph toolbar. Scope to local state only — server mutations are not reversible."
    }
  ]
}

