1	import { createBrowserRouter, Navigate } from "react-router-dom";
2	import { AppLayout } from "./App";
3	import { routerFuture } from "./routerFuture";
4	import MarketList from "@/routes/MarketList";
5	import MarketDetail from "@/routes/MarketDetail";
6	import Portfolio from "@/routes/Portfolio";
7	import System from "@/routes/System";
8	import { CreateMarketForm } from "@/features/market/CreateMarketForm";
9	
10	export const router = createBrowserRouter(
11	  [
12	    {
13	      element: <AppLayout />,
14	      children: [
15	        { index: true, element: <Navigate to="/markets" replace /> },
16	        { path: "markets", element: <MarketList /> },
17	        { path: "markets/new", element: <CreateMarketForm /> },
18	        { path: "markets/:marketId", element: <MarketDetail /> },
19	        { path: "portfolio", element: <Portfolio /> },
20	        { path: "system", element: <System /> },
21	      ],
22	    },
23	  ],
24	  {
25	    future: routerFuture,
26	  },
27	);
28

1	import { useState } from "react";
2	import { useParams } from "react-router-dom";
3	import { useMarket, useMarketEvents, useAccountRisk } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
7	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
8	import { formatCurrency, timeUntil, truncateHash, formatRelativeTime } from "@/lib/utils/format";
9	import { AssumptionProvider } from "@/features/assumptions/AssumptionContext";
10	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
11	import { HistoryProvider } from "@/features/history/HistoryContext";
12	import { UndoRedoToolbar } from "@/features/history/UndoRedoToolbar";
13	import { ForceDirectedGraph } from "@/features/graph/ForceDirectedGraph";
14	import { JunctionTreePanel } from "@/features/graph/JunctionTreePanel";
15	import { DiscussionThread } from "@/features/market/DiscussionThread";
16	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
17	import { EventTradePanel } from "@/features/trading/EventTradePanel";
18	import { CptPanel } from "@/features/trading/CptPanel";
19	import type { MarketEvent } from "@/lib/api/types";
20	
21	export default function MarketDetail() {
22	  const { marketId } = useParams<{ marketId: string }>();
23	  const { session, isConfigured } = useSession();
24	  const { data, isLoading, error } = useMarket(marketId!);
25	  const events = useMarketEvents(marketId!);
26	  const accountRisk = useAccountRisk(session.accountId);
27	
28	  if (isLoading) return <LoadingPage />;
29	  if (error) return <ErrorMessage message={error instanceof Error ? error.message : "Market not found"} />;
30	  if (!data) return null;
31	
32	  const m = data.market;
33	
34	  return (
35	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
36	      <div>
37	        <div style={{ display: "flex", gap: "var(--space-md)", alignItems: "center", marginBottom: "var(--space-sm)" }}>
38	          <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>{m.title}</h1>
39	          <StatusBadge status={m.status} />
40	        </div>
41	        <p style={{ color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>{m.description}</p>
42	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
43	          <span>Volume: {formatCurrency(m.volume)}</span>
44	          <span>Liquidity: {formatCurrency(m.liquidity)}</span>
45	          <span>Expires: {timeUntil(m.expires_at)}</span>
46	        </div>
47	      </div>
48	
49	      <ProbabilityBar outcomes={m.outcomes} marginals={m.marginals} />
50	
51	      <PositionCard marketId={m.id} accountRisk={accountRisk.data} isConfigured={isConfigured} />
52	
53	      <ResolveMarketPanel market={m} />
54	
55	      {m.status === "active" ? (
56	        <HistoryProvider>
57	          <AssumptionProvider>
58	            <UndoRedoToolbar />
59	            <AssumptionPanel market={m} />
60	            <CptPanel market={m} />
61	            <EventTradePanel market={m} />
62	            <DiscussionThread market={m} />
63	            <ForceDirectedGraph focusMarketId={m.id} />
64	          </AssumptionProvider>
65	        </HistoryProvider>
66	      ) : (
67	        <>
68	          <CptPanel market={m} />
69	          <EventTradePanel market={m} />
70	          <DiscussionThread market={m} />
71	          <ForceDirectedGraph focusMarketId={m.id} />
72	        </>
73	      )}
74	
75	      {/* Event Journal */}
76	      <div>
77	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Event Journal</h2>
78	        {events.isLoading && <LoadingPage />}
79	        {events.data && events.data.events.length === 0 && (
80	          <span style={{ color: "var(--color-text-muted)", fontSize: "0.85rem" }}>No events yet.</span>
81	        )}
82	        {events.data && events.data.events.length > 0 && (
83	          <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
84	            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
85	              <thead>
86	                <tr style={{ background: "var(--color-bg-hover)" }}>
87	                  <th style={thStyle}>Seq</th>
88	                  <th style={thStyle}>Type</th>
89	                  <th style={thStyle}>Hash</th>
90	                  <th style={thStyle}>Time</th>
91	                </tr>
92	              </thead>
93	              <tbody>
94	                {events.data.events.map((e) => (
95	                  <EventRow key={e.eventId} event={e} />
96	                ))}
97	              </tbody>
98	            </table>
99	          </div>
100	        )}
101	      </div>
