232	export function ForceDirectedGraph({
233	  focusMarketId,
234	  conditionalEdges = [],
235	  onNodeClick,
236	}: ForceDirectedGraphProps) {
237	  const { data: marketsData, isLoading } = useMarkets();
238	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
239	
240	  const markets = marketsData?.markets ?? [];
241	  const cliques = engineStats?.cliques.cliques ?? [];
242	
243	  // Derive force graph input nodes
244	  const forceInputNodes = useMemo(
245	    () => markets.map((m: MarketSummary) => ({ id: m.id, title: m.title, status: m.status })),
246	    [markets],
247	  );
248	
249	  // Derive edges from cliques + conditional edges
250	  const forceInputLinks = useMemo(() => {
251	    const cliqueEdges = deriveEdgesFromCliques(cliques);
252	    return mergeEdges(cliqueEdges, conditionalEdges);
253	  }, [cliques, conditionalEdges]);
254	
255	  const graphOptions = useMemo(() => ({ width: SVG_WIDTH, height: SVG_HEIGHT }), []);
256	  const { positions, getSimulation, getNodes, flushPositions } = useForceGraph(
257	    forceInputNodes,
258	    forceInputLinks,
259	    graphOptions,
260	  );
261	
262	  // Build position lookup
263	  const nodePositionMap = useMemo(() => {
264	    const map = new Map<string, { x: number; y: number }>();
265	    for (const np of positions.nodes) {
266	      map.set(np.id, { x: np.x, y: np.y });
267	    }
268	    return map;
269	  }, [positions]);
270	
271	  // Focus-connected set: focusMarketId + all nodes sharing an edge with it
272	  const connectedToFocus = useMemo(() => {
273	    if (!focusMarketId) return null;
274	    const set = new Set<string>([focusMarketId]);
275	    for (const link of forceInputLinks) {
276	      const src = typeof link.source === "string" ? link.source : link.source;
277	      const tgt = typeof link.target === "string" ? link.target : link.target;
278	      if (src === focusMarketId) set.add(tgt);
279	      if (tgt === focusMarketId) set.add(src);
280	    }
281	    return set;
282	  }, [focusMarketId, forceInputLinks]);
283	
284	  // --- Zoom behavior ---
285	  const svgRef = useRef<SVGSVGElement>(null);
286	  const gRef = useRef<SVGGElement>(null);
287	
288	  useEffect(() => {
289	    const svgEl = svgRef.current;
290	    if (!svgEl) return;
291	
292	    const zoomBehavior = d3Zoom<SVGSVGElement, unknown>()
293	      .scaleExtent([0.3, 3])
294	      .on("zoom", (event) => {
295	        if (gRef.current) {
296	          gRef.current.setAttribute("transform", event.transform.toString());
297	        }
298	      });
299	
300	    const sel = select(svgEl);
301	    sel.call(zoomBehavior);
302	
303	    // Double-click to reset zoom
304	    sel.on("dblclick.zoom", () => {
305	      sel.call(zoomBehavior.transform, zoomIdentity);
306	    });
307	
308	    return () => {
309	      sel.on(".zoom", null);
310	    };
311	  }, []);
312	
313	  // --- Drag behavior ---
314	  useEffect(() => {
315	    const svgEl = svgRef.current;
316	    if (!svgEl || markets.length === 0) return;
317	
318	    const nodeGroups = select(svgEl).selectAll<SVGGElement, unknown>("g[data-node-id]");
319	
320	    const dragBehavior = d3Drag<SVGGElement, unknown>()
321	      .on("start", function (event) {
322	        const nodeId = this.getAttribute("data-node-id");
323	        if (!nodeId) return;
324	        const sim = getSimulation();
325	        const nodes = getNodes();
326	        const node = nodes.find((n) => n.id === nodeId);
327	        if (!node || !sim) return;
328	        if (!event.active) sim.alphaTarget(0.3).restart();
329	        node.fx = node.x;
330	        node.fy = node.y;
331	      })
332	      .on("drag", function (event) {
333	        const nodeId = this.getAttribute("data-node-id");
334	        if (!nodeId) return;
335	        const nodes = getNodes();
336	        const node = nodes.find((n) => n.id === nodeId);
337	        if (!node) return;
338	        node.fx = event.x;
339	        node.fy = event.y;
340	        flushPositions();
341	      })
342	      .on("end", function (event) {
343	        const nodeId = this.getAttribute("data-node-id");
344	        if (!nodeId) return;
345	        const sim = getSimulation();
346	        const nodes = getNodes();
347	        const node = nodes.find((n) => n.id === nodeId);
348	        if (!node || !sim) return;
349	        if (!event.active) sim.alphaTarget(0);
350	        node.fx = null;
351	        node.fy = null;
352	      });
353	
354	    nodeGroups.call(dragBehavior);
355	
356	    return () => {
357	      nodeGroups.on(".drag", null);
358	    };
359	  }, [positions, markets.length, getSimulation, getNodes, flushPositions]);
360	
361	  // --- Loading state ---
362	  if (isLoading) {
363	    return (
364	      <div style={panelStyle}>
365	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
366	          Loading network...
367	        </div>
368	      </div>
369	    );
370	  }
371	
372	  if (markets.length === 0) {
373	    return (
374	      <div style={panelStyle}>
375	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
376	          No markets to visualize.
377	        </div>
378	      </div>
379	    );
380	  }
381	
382	  // Resolve link endpoints to positions
383	  const resolvedLinks = forceInputLinks
384	    .map((link) => {
385	      const src = typeof link.source === "string" ? link.source : link.source;
386	      const tgt = typeof link.target === "string" ? link.target : link.target;
387	      const srcPos = nodePositionMap.get(src);
388	      const tgtPos = nodePositionMap.get(tgt);
389	      if (!srcPos || !tgtPos) return null;
390	      const isHighlighted = focusMarketId != null && (src === focusMarketId || tgt === focusMarketId);
391	      return { src, tgt, srcPos, tgtPos, isHighlighted };
392	    })
393	    .filter((l): l is NonNullable<typeof l> => l != null);
394	
395	  return (
396	    <div style={panelStyle}>
397	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
398	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
399	          Bayesian Network
400	        </h3>
401	        <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
402	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
403	          {conditionalEdges.length > 0 && ` \u00B7 ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
404	          {cliques.length > 0 && ` \u00B7 ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
405	          {engineStats && ` \u00B7 JT width ${engineStats.cliques.junction_tree_width}`}
406	        </div>
407	      </div>
408	
409	      <svg
410	        ref={svgRef}
411	        viewBox={`0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`}
412	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
413	      >
414	        <g ref={gRef}>
415	          {/* Clique overlays (behind edges/nodes) */}
416	          {cliques.map((c) => (
417	            <CliqueOverlay key={c.id} clique={c} nodePositions={nodePositionMap} />
418	          ))}
419	
420	          {/* Edges */}
421	          {resolvedLinks.map((link, i) => (
422	            <EdgeLine
423	              key={`${link.src}-${link.tgt}-${i}`}
424	              x1={link.srcPos.x}
425	              y1={link.srcPos.y}
426	              x2={link.tgtPos.x}
427	              y2={link.tgtPos.y}
428	              isHighlighted={link.isHighlighted}
429	            />
430	          ))}
431	
432	          {/* Market nodes */}
433	          {forceInputNodes.map((node) => {
434	            const pos = nodePositionMap.get(node.id);
435	            if (!pos) return null;
436	            const isFocus = node.id === focusMarketId;
437	            const isDimmed = connectedToFocus != null && !connectedToFocus.has(node.id);
438	            return (
439	              <NodeWithDetail
440	                key={node.id}
441	                x={pos.x}
442	                y={pos.y}
443	                node={node}
444	                isFocus={isFocus}
445	                isDimmed={isDimmed}
446	                onClick={onNodeClick ? () => onNodeClick(node.id) : undefined}
447	              />
448	            );
449	          })}
450	        </g>
451	      </svg>
452	
453	      {/* Legend */}
454	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
455	        <span>
456	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
457	          Active
458	        </span>
459	        <span>
460	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-info)", marginRight: 4 }} />
461	          Resolved
462	        </span>
463	        {conditionalEdges.length > 0 && (
464	          <span>
465	            <span style={{ display: "inline-block", width: 16, height: 2, background: "var(--color-primary)", marginRight: 4, verticalAlign: "middle" }} />
466	            Conditional dependency
467	          </span>
468	        )}
469	        {cliques.length > 0 && (
470	          <span>
471	            <span style={{ display: "inline-block", width: 12, height: 12, border: "1px dashed var(--color-primary)", borderRadius: 3, marginRight: 4, verticalAlign: "middle", opacity: 0.5 }} />
472	            Junction tree clique
473	          </span>
474	        )}
475	      </div>
476	    </div>
477	  );
478	}
