33	    volume: m.volume,
34	    expires_at: m.expires_at,
35	    position: posMap.get(m.id) ?? { x: 0, y: 0 },
36	  }));
37	
38	  const exportEdges: NetworkExportEdge[] = [
39	    ...cliqueEdges.map(
40	      (e): NetworkExportEdge => ({ source: e.source, target: e.target, type: "clique" }),
41	    ),
42	    ...conditionalEdges.map(
43	      (e): NetworkExportEdge => ({ source: e.from, target: e.to, type: "conditional" }),
44	    ),
45	  ];
46	
47	  return {
48	    version: NETWORK_EXPORT_VERSION,
49	    exportedAt: new Date().toISOString(),
50	    metadata: {
51	      nodeCount: exportNodes.length,
52	      edgeCount: exportEdges.length,
53	      cliqueCount: cliques.length,
54	    },
55	    nodes: exportNodes,
56	    edges: exportEdges,
57	    cliques,
58	  };
59	}
