9	// --------------- Type guards ---------------
10	
11	function isRecord(v: unknown): v is Record<string, unknown> {
12	  return typeof v === "object" && v !== null && !Array.isArray(v);
13	}
14	
15	function isStringArray(v: unknown): v is string[] {
16	  return Array.isArray(v) && v.every((x) => typeof x === "string");
17	}
18	
19	function isValidNode(v: unknown): v is NetworkExportNode {
20	  if (!isRecord(v)) return false;
21	  if (typeof v.id !== "string" || typeof v.title !== "string") return false;
22	  if (typeof v.status !== "string") return false;
23	  if (typeof v.liquidity !== "number" || typeof v.volume !== "number") return false;
24	  if (typeof v.expires_at !== "string") return false;
25	  if (!isRecord(v.position)) return false;
26	  if (typeof v.position.x !== "number" || typeof v.position.y !== "number") return false;
27	  return true;
28	}
29	
30	function isValidEdge(v: unknown): v is NetworkExportEdge {
31	  if (!isRecord(v)) return false;
32	  if (typeof v.source !== "string" || typeof v.target !== "string") return false;
33	  if (v.type !== "clique" && v.type !== "conditional") return false;
34	  return true;
35	}
36	
37	function isValidClique(v: unknown): v is CliqueSummary {
38	  if (!isRecord(v)) return false;
39	  if (typeof v.id !== "string") return false;
40	  if (!isStringArray(v.nodes)) return false;
41	  if (typeof v.size !== "number" || typeof v.states !== "number") return false;
42	  return true;
43	}
44	
45	export type ImportResult =
46	  | { ok: true; data: NetworkExportSchema }
47	  | { ok: false; error: string };
48	
49	/**
50	 * Validate a parsed JSON value against NetworkExportSchema.
51	 */
52	export function validateNetworkExport(raw: unknown): ImportResult {
53	  if (!isRecord(raw)) {
54	    return { ok: false, error: "File is not a valid JSON object." };
55	  }
56	
57	  if (raw.version !== NETWORK_EXPORT_VERSION) {
58	    return {
59	      ok: false,
60	      error: `Unsupported version: expected ${NETWORK_EXPORT_VERSION}, got ${String(raw.version)}.`,
61	    };
62	  }
63	
64	  if (typeof raw.exportedAt !== "string") {
65	    return { ok: false, error: "Missing exportedAt timestamp." };
66	  }
67	
68	  if (!isRecord(raw.metadata)) {
69	    return { ok: false, error: "Missing metadata object." };
70	  }
71	
72	  if (!Array.isArray(raw.nodes) || !raw.nodes.every(isValidNode)) {
73	    return { ok: false, error: "Invalid or missing nodes array." };
74	  }
75	
76	  if (!Array.isArray(raw.edges) || !raw.edges.every(isValidEdge)) {
77	    return { ok: false, error: "Invalid or missing edges array." };
78	  }
79	
80	  if (!Array.isArray(raw.cliques) || !raw.cliques.every(isValidClique)) {
81	    return { ok: false, error: "Invalid or missing cliques array." };
82	  }
83	
84	  return { ok: true, data: raw as unknown as NetworkExportSchema };
85	}
86	
87	/**
88	 * Read a File object and validate its contents as a NetworkExportSchema.
89	 * Returns a promise that resolves with the import result.
90	 */
91	export function readAndValidateFile(file: File): Promise<ImportResult> {
92	  return new Promise((resolve) => {
93	    const reader = new FileReader();
94	    reader.onload = () => {
95	      try {
96	        const parsed: unknown = JSON.parse(reader.result as string);
97	        resolve(validateNetworkExport(parsed));
98	      } catch {
99	        resolve({ ok: false, error: "File is not valid JSON." });
100	      }
101	    };
102	    reader.onerror = () => {
103	      resolve({ ok: false, error: "Failed to read file." });
104	    };
105	    reader.readAsText(file);
106	  });
107	}
