241	export function BayesNetGraph({
242	  focusMarketId,
243	  conditionalEdges = [],
244	}: BayesNetGraphProps) {
245	  const { data: marketsData, isLoading } = useMarkets();
246	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
247	
248	  // --- Snapshot state for imported networks ---
249	  const [snapshot, setSnapshot] = useState<NetworkExportSchema | null>(null);
250	  const [importError, setImportError] = useState<string | null>(null);
251	  const fileInputRef = useRef<HTMLInputElement>(null);
252	
253	  const liveMarkets = marketsData?.markets ?? [];
254	  const markets = snapshot
255	    ? snapshot.nodes.map((n) => ({
256	        id: n.id,
257	        title: n.title,
258	        status: n.status,
259	        liquidity: n.liquidity,
260	        volume: n.volume,
261	        expires_at: n.expires_at,
262	      }))
263	    : liveMarkets;
264	
265	  const nodes = useMemo(
266	    () =>
267	      snapshot
268	        ? snapshot.nodes.map((n) => ({
269	            id: n.id,
270	            title: n.title.length > 28 ? n.title.slice(0, 26) + "…" : n.title,
271	            x: n.position.x,
272	            y: n.position.y,
273	            marginals: {} as Record<string, number>,
274	            outcomeName: "",
275	            status: n.status,
276	          }))
277	        : layoutNodes(liveMarkets),
278	    [snapshot, liveMarkets],
279	  );
280	  const cliques = snapshot ? snapshot.cliques : (engineStats?.cliques.cliques ?? []);
281	
282	  // --- Animation: detect assumption changes and trigger propagation ---
283	  const { assumptions } = useAssumptions();
284	  const { animatingNodes, animatingEdges, evidenceNodeId, triggerAnimation, cancelAnimation } =
285	    useAnimationPropagation();
286	  const prevAssumptionsRef = useRef(assumptions);
287	
288	  // Derive all edges for BFS traversal (clique-derived + conditional)
289	  const allEdges = useMemo(
290	    () => mergeEdges(deriveEdgesFromCliques(cliques), conditionalEdges),
291	    [cliques, conditionalEdges],
292	  );
293	
294	  useEffect(() => {
295	    const prev = prevAssumptionsRef.current;
296	    prevAssumptionsRef.current = assumptions;
297	
298	    if (prev === assumptions) return;
299	
300	    // Find the assumption that was added or removed
301	    const added = assumptions.find(
302	      (a) => !prev.some((p) => p.variableId === a.variableId && p.outcomeId === a.outcomeId),
303	    );
304	    const removed = prev.find(
305	      (p) => !assumptions.some((a) => a.variableId === p.variableId && a.outcomeId === p.outcomeId),
306	    );
307	
308	    const changedVariableId = added?.variableId ?? removed?.variableId;
309	    if (!changedVariableId) return;
310	
311	    // Find the node (market) that corresponds to the changed variable.
312	    // Assumption variableId may match market id (MarketSummary only has id).
313	    const evidenceNode = markets.find((m) => m.id === changedVariableId);
314	    if (evidenceNode && allEdges.length > 0) {
315	      triggerAnimation(evidenceNode.id, allEdges);
316	    }
317	  }, [assumptions, markets, allEdges, triggerAnimation]);
318	
319	  // Cancel animation on unmount
320	  useEffect(() => cancelAnimation, [cancelAnimation]);
321	
322	  // --- Export handler ---
323	  const handleExport = useCallback(() => {
324	    const cliqueEdges = deriveEdgesFromCliques(cliques);
325	    const data = buildNetworkExport(markets as MarketSummary[], nodes, cliqueEdges, conditionalEdges, cliques);
326	    const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
327	    downloadJson(data, `bayes-network-${ts}.json`);
328	  }, [markets, nodes, cliques, conditionalEdges]);
329	
330	  // --- Import handler ---
331	  const handleImportFile = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
332	    const file = e.target.files?.[0];
333	    if (!file) return;
334	    setImportError(null);
335	    const result = await readAndValidateFile(file);
336	    if (result.ok) {
337	      setSnapshot(result.data);
338	    } else {
339	      setImportError(result.error);
340	    }
341	    // Reset so the same file can be re-selected
342	    e.target.value = "";
343	  }, []);
344	
345	  if (isLoading) {
346	    return (
347	      <div style={panelStyle}>
348	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
349	          Loading network...
350	        </div>
351	      </div>
352	    );
353	  }
354	
355	  if (markets.length === 0) {
356	    return (
357	      <div style={panelStyle}>
358	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
359	          No markets to visualize.
360	        </div>
361	      </div>
362	    );
363	  }
364	
365	  // Compute SVG viewBox from node positions
366	  const xs = nodes.map((n) => n.x);
367	  const ys = nodes.map((n) => n.y);
368	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
369	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
370	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
371	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
372	
373	  return (
374	    <div style={panelStyle}>
375	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
376	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
377	          Bayesian Network{snapshot ? " (imported)" : ""}
378	        </h3>
379	
380	        <div style={{ display: "flex", alignItems: "center", gap: "var(--space-sm)" }}>
381	          {/* Export / Import buttons */}
382	          <div style={{ display: "flex", gap: 4 }}>
383	            <button
384	              type="button"
385	              onClick={handleExport}
386	              style={smallButtonStyle}
387	              title="Export network as JSON"
388	            >
389	              Export
390	            </button>
391	            <button
392	              type="button"
393	              onClick={() => fileInputRef.current?.click()}
394	              style={smallButtonStyle}
395	              title="Import network from JSON"
396	            >
397	              Import
398	            </button>
399	            {snapshot && (
400	              <button
401	                type="button"
402	                onClick={() => { setSnapshot(null); setImportError(null); }}
403	                style={{ ...smallButtonStyle, color: "var(--color-danger)" }}
404	                title="Return to live network"
405	              >
406	                Clear
407	              </button>
408	            )}
409	            <input
410	              ref={fileInputRef}
411	              type="file"
412	              accept=".json"
413	              style={{ display: "none" }}
414	              onChange={handleImportFile}
415	            />
416	          </div>
417	
418	          <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
419	            {markets.length} variable{markets.length !== 1 ? "s" : ""}
420	            {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
421	            {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
422	            {engineStats && !snapshot && ` · JT width ${engineStats.cliques.junction_tree_width}`}
423	          </div>
424	        </div>
425	      </div>
426	
427	      {importError && (
428	        <div style={{ fontSize: "0.75rem", color: "var(--color-danger)", marginBottom: "var(--space-sm)" }}>
429	          Import failed: {importError}
430	        </div>
431	      )}
432	
433	      <svg
434	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
435	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
436	      >
437	        <defs>
438	          {/* Glow filter for evidence node */}
439	          <filter id="evidence-glow" x="-30%" y="-30%" width="160%" height="160%">
440	            <feGaussianBlur in="SourceAlpha" stdDeviation="6" result="blur" />
441	            <feFlood floodColor="var(--color-primary)" floodOpacity="0.6" result="color" />
442	            <feComposite in="color" in2="blur" operator="in" result="glow" />
443	            <feMerge>
444	              <feMergeNode in="glow" />
445	              <feMergeNode in="SourceGraphic" />
446	            </feMerge>
447	          </filter>
448	          {/* Highlight filter for nodes reached by propagation wave */}
449	          <filter id="propagation-highlight" x="-15%" y="-15%" width="130%" height="130%">
450	            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor="var(--color-info)" floodOpacity="0.5" />
451	          </filter>
452	        </defs>
453	        <style>{`
454	          @keyframes evidence-pulse {
455	            0% { opacity: 0.7; }
456	            50% { opacity: 1; }
457	            100% { opacity: 0.7; }
458	          }
459	          @keyframes propagation-arrive {
