461	            50% { opacity: 1; transform: scale(1.02); }
462	            100% { opacity: 1; transform: scale(1); }
463	          }
464	          @keyframes edge-flow {
465	            0% { stroke-dashoffset: 16; }
466	            100% { stroke-dashoffset: 0; }
467	          }
468	          .evidence-node { animation: evidence-pulse 0.8s ease-in-out infinite; filter: url(#evidence-glow); }
469	          .propagation-node { animation: propagation-arrive 0.3s ease-out forwards; filter: url(#propagation-highlight); }
470	          .propagation-edge { animation: edge-flow 0.4s linear infinite; }
471	        `}</style>
472	
473	        {/* Clique overlays (behind edges/nodes) */}
474	        {cliques.map((c) => (
475	          <CliqueOverlay key={c.id} clique={c} nodes={nodes} />
476	        ))}
477	
478	        {/* Conditional edges */}
479	        {conditionalEdges.map((e, i) => (
480	          <EdgeLine key={`${e.from}-${e.to}-${i}`} from={e.from} to={e.to} nodes={nodes} />
481	        ))}
482	
483	        {/* Animated propagation edges */}
484	        {animatingEdges.size > 0 && allEdges.map((e) => {
485	          const ek = e.source < e.target ? `${e.source}::${e.target}` : `${e.target}::${e.source}`;
486	          if (!animatingEdges.has(ek)) return null;
487	          const a = nodes.find((n) => n.id === e.source);
488	          const b = nodes.find((n) => n.id === e.target);
489	          if (!a || !b) return null;
490	          const dx = b.x - a.x;
491	          const dy = b.y - a.y;
492	          const dist = Math.sqrt(dx * dx + dy * dy);
493	          if (dist === 0) return null;
494	          const ux = dx / dist;
495	          const uy = dy / dist;
496	          const sx = a.x + ux * (NODE_W / 2 + 4);
497	          const sy = a.y + uy * (NODE_H / 2 + 4);
498	          const ex = b.x - ux * (NODE_W / 2 + 8);
499	          const ey = b.y - uy * (NODE_H / 2 + 8);
500	          return (
501	            <line
502	              key={`anim-${ek}`}
503	              x1={sx} y1={sy} x2={ex} y2={ey}
504	              stroke="var(--color-info)"
505	              strokeWidth={2.5}
506	              strokeDasharray="8 8"
507	              opacity={0.8}
508	              className="propagation-edge"
509	            />
510	          );
511	        })}
512	
513	        {/* Market nodes */}
514	        {nodes.map((node) => {
515	          const isEvidence = node.id === evidenceNodeId;
516	          const isAnimating = animatingNodes.has(node.id);
517	          const animClass = isEvidence
518	            ? "evidence-node"
519	            : isAnimating
520	              ? "propagation-node"
521	              : undefined;
522	          return (
523	            <NodeWithDetail
524	              key={node.id}
525	              node={node}
526	              isFocus={node.id === focusMarketId}
527	              animationClass={animClass}
528	            />
529	          );
530	        })}
531	      </svg>
532	
533	      {/* Legend */}
534	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
535	        <span>
536	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
