3	/** Generic command interface for undo/redo operations */
4	export interface Command {
5	  /** Human-readable description of the action */
6	  readonly description: string;
7	  /** Execute the action */
8	  execute(): void;
9	  /** Reverse the action */
10	  undo(): void;
11	}
12	
13	// ---------------------------------------------------------------------------
14	// Assumption commands
15	// ---------------------------------------------------------------------------
16	
17	export class AssumptionAddCommand implements Command {
18	  readonly description: string;
19	  private readonly assumption: Assumption;
20	  private readonly previousAssumption: Assumption | undefined;
21	  private readonly doAdd: (a: Assumption) => void;
22	  private readonly doRemove: (variableId: string) => void;
23	  private readonly doAddBack: (a: Assumption) => void;
24	
25	  constructor(opts: {
26	    assumption: Assumption;
27	    previousAssumption: Assumption | undefined;
28	    addAssumption: (a: Assumption) => void;
29	    removeAssumption: (variableId: string) => void;
30	  }) {
31	    this.assumption = opts.assumption;
32	    this.previousAssumption = opts.previousAssumption;
33	    this.doAdd = opts.addAssumption;
34	    this.doRemove = opts.removeAssumption;
35	    this.doAddBack = opts.addAssumption;
36	    this.description = `Assume ${opts.assumption.label} for ${opts.assumption.variableId}`;
37	  }
38	
39	  execute() {
40	    this.doAdd(this.assumption);
41	  }
42	
43	  undo() {
44	    if (this.previousAssumption) {
45	      this.doAddBack(this.previousAssumption);
46	    } else {
47	      this.doRemove(this.assumption.variableId);
48	    }
49	  }
50	}
51	
52	export class AssumptionRemoveCommand implements Command {
53	  readonly description: string;
54	  private readonly removedAssumption: Assumption;
55	  private readonly doAdd: (a: Assumption) => void;
56	  private readonly doRemove: (variableId: string) => void;
57	
58	  constructor(opts: {
59	    removedAssumption: Assumption;
60	    addAssumption: (a: Assumption) => void;
61	    removeAssumption: (variableId: string) => void;
62	  }) {
63	    this.removedAssumption = opts.removedAssumption;
64	    this.doAdd = opts.addAssumption;
65	    this.doRemove = opts.removeAssumption;
66	    this.description = `Remove assumption for ${opts.removedAssumption.variableId}`;
67	  }
68	
69	  execute() {
70	    this.doRemove(this.removedAssumption.variableId);
71	  }
72	
73	  undo() {
74	    this.doAdd(this.removedAssumption);
75	  }
76	}
77	
78	export class AssumptionClearAllCommand implements Command {
79	  readonly description = "Clear all assumptions";
80	  private readonly previousAssumptions: Assumption[];
81	  private readonly doSetAll: (assumptions: Assumption[]) => void;
82	  private readonly doClear: () => void;
83	
84	  constructor(opts: {
85	    previousAssumptions: Assumption[];
86	    setAllAssumptions: (assumptions: Assumption[]) => void;
87	    clearAll: () => void;
88	  }) {
89	    this.previousAssumptions = [...opts.previousAssumptions];
90	    this.doSetAll = opts.setAllAssumptions;
91	    this.doClear = opts.clearAll;
92	  }
93	
94	  execute() {
95	    this.doClear();
96	  }
97	
98	  undo() {
99	    this.doSetAll(this.previousAssumptions);
100	  }
101	}
