103	// ---------------------------------------------------------------------------
104	// Probability edit draft commands
105	// ---------------------------------------------------------------------------
106	
107	export interface DraftEdit {
108	  entryIndex: number;
109	  outcomeId: string;
110	  probability: number;
111	  context: Array<{ variableId: string; outcomeId: string }>;
112	  previousProbability: number;
113	  /** True if a draft already existed for this cell before this edit */
114	  hadPriorDraft?: boolean;
115	}
116	
117	export class ProbabilityEditCommand implements Command {
118	  readonly description: string;
119	  private readonly drafts: DraftEdit[];
120	  private readonly applyDrafts: (drafts: DraftEdit[]) => void;
121	  private readonly revertDrafts: (drafts: DraftEdit[]) => void;
122	
123	  constructor(opts: {
124	    drafts: DraftEdit[];
125	    applyDrafts: (drafts: DraftEdit[]) => void;
126	    revertDrafts: (drafts: DraftEdit[]) => void;
127	    description?: string;
128	  }) {
129	    this.drafts = opts.drafts;
130	    this.applyDrafts = opts.applyDrafts;
131	    this.revertDrafts = opts.revertDrafts;
132	    this.description = opts.description ?? `Edit ${opts.drafts.length} probability value(s)`;
133	  }
134	
135	  execute() {
136	    this.applyDrafts(this.drafts);
137	  }
138	
139	  undo() {
140	    this.revertDrafts(this.drafts);
141	  }
142	}
